/**
 * Index counter|target -> entree, pour acces O(1) durant la simulation.
 */
const CHAMPION_COUNTERS_MAP = new Map();
CHAMPION_COUNTERS.forEach((entry) => {
  CHAMPION_COUNTERS_MAP.set(`${entry.counter}|${entry.target}`, entry);
});

/**
 * Renvoie l'entree de counter entre deux champions (par id), si elle existe.
 * direction: from -> to (from contre to). Renvoie null si aucune donnee.
 */
function getCounterEntry(fromId, toId) {
  return CHAMPION_COUNTERS_MAP.get(`${fromId}|${toId}`) || null;
}

/**
 * Liste des champions que ce champion contre (counter -> target).
 */
function getCountersFor(championId) {
  return CHAMPION_COUNTERS.filter((e) => e.counter === championId);
}

/**
 * Liste des champions qui contrent ce champion (target).
 */
function getCounteredBy(championId) {
  return CHAMPION_COUNTERS.filter((e) => e.target === championId);
}
